import {DocumentSet,Document} from "@hoge1e3/ngram";
import {file} from "@acepad/here";
import pNode from "petit-node";
import * as fs from "fs";
import * as path from "path";
import ignore from "ignore";
const timeout=(t)=>new Promise(s=>setTimeout(s,t));
let s;
const excludes={".git":1,".gsync":1};
export async function traverseHere(f){
  const trs=(s)=>s.replace(/\/$/,"");
  const df=pNode.
    getDeviceManager().
    df().map(d=>
    trs(d.mountPoint));
  await fs.promises.readdir(f.path());
  return traverseNotIgnored(f.path());
  function* traverseNotIgnored(dir, ig = ignore()) {
    const gitignore = path.join(dir, ".gitignore");
    let localIg = ig;
    if (fs.existsSync(gitignore)) {
      const rules = fs.readFileSync(gitignore, "utf8");
      localIg = ignore().add(ig).add(rules);
    }
    for (const name of fs.readdirSync(dir)) {
      const full = path.join(dir, name);
      if(excludes.hasOwnProperty(name)||
        df.includes(trs(full)))continue;
      const rel = name;
      if (localIg.ignores(rel)) continue;
      const st = fs.statSync(full);
      if (st.isDirectory()) {
        //yield file(full);
        yield* traverseNotIgnored(full, localIg);
      } else {
        yield file(full);
      }
    }
  }
}

export async function init(dir) {
    if (s) return;
    const exts=[".js",".ts",".json"];
    dir=file(dir);
    s=new DocumentSet();
    console.log("suggest-worker start");
    let i=0;
    for(let f of await traverseHere(dir)){
        i++;
        if(i%10==0)await timeout(1);
        if(!exts.includes(f.ext()))continue;
        let d=new Document(f.relPath(dir),f.text());
        s.addDocument(d);
    }
    //console.log("para-w1",i);
    for(i=0;i<300000;i++){
        let p=s.expand();
        //sug.text(p);
        if(p<4)break;
        if(i%10==0)await timeout(1);
        if(i%5000==0) {
        //console.log("para2",i,p);
            s.calcCount();
        }
    }
    s.calcCount();
}
export async function predict(text,offset){// text:string, offset:number
    if (!s) throw new Error("Call init first.");
    const d=new Document("p",text);
    const c=await s.predict(d,offset);
    return c;
}